319‚Üí                jetpackBrandingUtils.initJetpackBannerAnimation(jetpackBannerView, scrollableView)
320‚Üí                binding?.jetpackBanner?.jetpackBannerText?.text = uiHelpers.getTextOfUiString(
321‚Üí                    requireContext(),
322‚Üí                    jetpackBrandingUtils.getBrandingTextForScreen(screen)
