 11‚Üíimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.APPLINK_SCHEME
 12‚Üíimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.HOST_WORDPRESS_COM
 13‚Üíimport org.wordpress.android.ui.deeplinks.DeepLinkingIntentReceiverViewModel.Companion.SITE_DOMAIN
 14‚Üíimport org.wordpress.android.ui.jetpackoverlay.JetpackFeatureRemovalPhaseHelper
 15‚Üíimport org.wordpress.android.ui.stats.StatsTimeframe
 16‚Üíimport org.wordpress.android.util.UriWrapper
 17‚Üíimport javax.inject.Inject
 18‚Üí
 19‚Üíclass StatsLinkHandler
 20‚Üí@Inject constructor(
 21‚Üí    private val deepLinkUriUtils: DeepLinkUriUtils,
 22‚Üí    private val jetpackFeatureRemovalPhaseHelper: JetpackFeatureRemovalPhaseHelper
 23‚Üí) : DeepLinkHandler {
 24‚Üí    /**
 25‚Üí     * Builds navigate action from URL like:
 26‚Üí     * https://wordpress.com/stats/$timeframe/$site
 27‚Üí     * where timeframe and site are optional
 28‚Üí     * or
 29‚Üí     * wordpress://stats
 30‚Üí     */
 31‚Üí    override fun buildNavigateAction(uri: UriWrapper): NavigateAction {
 32‚Üí        val pathSegments = uri.pathSegments
 33‚Üí        val length = pathSegments.size
 34‚Üí        val site = pathSegments.getOrNull(length - 1)?.toSite()
 35‚Üí        val statsTimeframe = pathSegments.getOrNull(length - 2)?.toStatsTimeframe()
 36‚Üí        return when {
 37‚Üí            jetpackFeatureRemovalPhaseHelper.shouldShowStaticPage() -> OpenJetpackStaticPosterView
 38‚Üí            site != null && statsTimeframe != null -> {
 39‚Üí                OpenStatsForSiteAndTimeframe(site, statsTimeframe)
 40‚Üí            }
 41‚Üí            site != null -> {
 42‚Üí                OpenStatsForSite(site)
 43‚Üí            }
 44‚Üí            statsTimeframe != null -> {
 45‚Üí                OpenStatsForTimeframe(statsTimeframe)
 46‚Üí            }
 47‚Üí            else -> {
 48‚Üí                // In other cases, launch stats with the current selected site.
 49‚Üí                OpenStats
 50‚Üí            }
 51‚Üí        }
 52‚Üí    }
 53‚Üí
 54‚Üí    /**
 55‚Üí     * Returns true if the URI should be handled by StatsLinkHandler.
 56‚Üí     * The handled links are `https://wordpress.com/stats/day/$site` and `wordpress://stats`
 57‚Üí     */
 58‚Üí    override fun shouldHandleUrl(uri: UriWrapper): Boolean {
 59‚Üí        return (uri.host == HOST_WORDPRESS_COM &&
 60‚Üí                uri.pathSegments.firstOrNull() == STATS_PATH) || uri.host == STATS_PATH
 61‚Üí    }
 62‚Üí
 63‚Üí    override fun stripUrl(uri: UriWrapper): String {
 64‚Üí        return buildString {
 65‚Üí            val offset = if (uri.host == STATS_PATH) {
 66‚Üí                append(APPLINK_SCHEME)
 67‚Üí                0
 68‚Üí            } else {
 69‚Üí                append("$HOST_WORDPRESS_COM/")
 70‚Üí                1
 71‚Üí            }
 72‚Üí            append(STATS_PATH)
 73‚Üí            val pathSegments = uri.pathSegments
 74‚Üí            val size = pathSegments.size
 75‚Üí            val statsTimeframe = if (size > offset) pathSegments.getOrNull(offset) else null
 76‚Üí            val hasSiteUrl = if (size > offset + 1) pathSegments.getOrNull(offset + 1) != null else false
 77‚Üí            if (statsTimeframe != null) {
 78‚Üí                append("/$statsTimeframe")
 79‚Üí            }
 80‚Üí            if (hasSiteUrl) {
 81‚Üí                append("/$SITE_DOMAIN")
 82‚Üí            }
 83‚Üí        }
 84‚Üí    }
 85‚Üí
 86‚Üí    /**
 87‚Üí     * Converts HOST name of a site to SiteModel. It finds the Site in the current local sites and matches the name
 88‚Üí     * to the host.
 89‚Üí     */
 90‚Üí    private fun String.toSite(): SiteModel? {
 91‚Üí        return deepLinkUriUtils.hostToSite(this)
 92‚Üí    }
 93‚Üí
 94‚Üí    private fun String.toStatsTimeframe(): StatsTimeframe? {
 95‚Üí        return when (this) {
 96‚Üí            "day" -> StatsTimeframe.DAY
 97‚Üí            "week" -> StatsTimeframe.WEEK
 98‚Üí            "month" -> StatsTimeframe.MONTH
 99‚Üí            "year" -> StatsTimeframe.YEAR
100‚Üí            "insights" -> StatsTimeframe.INSIGHTS
101‚Üí            "subscribers" -> StatsTimeframe.SUBSCRIBERS
102‚Üí            "traffic" -> StatsTimeframe.TRAFFIC
103‚Üí            else -> null
104‚Üí        }
105‚Üí    }
106‚Üí
107‚Üí    companion object {
108‚Üí        private const val STATS_PATH = "stats"
109‚Üí    }
110‚Üí}
